class Solution {
public:
    int solve(queue<int>& q) {
        if (q.size() == 0) return -1;
        int front = q.front();
        q.dequeue();
        for (int i = 0; i < q.size(); ++i) {
            if (front > q.front()) {
                q.dequeue();
                q.push_back(front);
                q.enqueue(front);
            } else {
                break;
            }
        }
        return front;
    }
};

