public:
    int solve(LinkedList<Integer> q) {
        if (q.isEmpty()) return -1;
        int front = (int) q.peekFirst();
        q.removeFirst();
        for (int i = 0; i < q.size(); i++) {
            if (front > (int) q.peekFirst()) {
                q.removeFirst();
                q.addLast(front);
                q.addFirst(front);
            } else {
                break;
            }
        }
        return front;
    }
};

